var e=`/api/documents`;async function t(e,t={}){let n=await fetch(e,{...t,credentials:`include`,headers:{...t.headers},signal:t.signal});if(!n.ok){let e=await n.json().catch(()=>({error:`Request failed`}));throw Error(e.error||`HTTP ${n.status}`)}return n.json()}var n={list:(n,r,i)=>t(`${e}?entity_id=${n}&entity_type=${r}`,{signal:i}),upload:(n,r,i,a)=>{let o=new FormData;return o.append(`file`,n),o.append(`entity_id`,String(r)),o.append(`entity_type`,i),t(e,{method:`POST`,body:o,signal:a})},download:t=>{window.open(`${e}/${t}/download`,`_blank`)},delete:(n,r)=>t(`${e}/${n}`,{method:`DELETE`,signal:r})};export{n as t};